UPDATE /* @SQLID=SUB0204_02-05#SQL003#SQL005 */
    CORDYS.T_IPO_PO_ORDER_DETAIL
SET
	ORDER_STATUS = #{statusAfter}
	,UPDATE_TIME = IFA_DATE_UTIL.IFA_GET_DATE
	,UPDATE_USER = #{userId}
	,SYS_ID = #{sysId}
WHERE
	ORDER_STATUS = #{statusBefore}

	AND NVL(UPDATE_TIME, CREATE_TIME) <= TO_DATE(#{sysDate}, 'yyyyMMddhh24miss')


	AND BUTEN_CODE || LPAD(ACCOUNT_NUMBER, 7, 0) || PRODUCT_CODE BETWEEN #{minKey} AND #{maxKey}

mapper.select:
SELECT /* @SQLID=SUB0204_02-05#SQL002 */ COUNT(1) FROM ETINTRA.BB_ACCEPT A INNER JOIN ETINTRA.BB_PRODUCT_MASTER B ON A.BB_PRODUCT_CODE = B.BB_PRODUCT_CODE AND A.BB_PRESENTATION_FROM = TO_NUMBER(TO_CHAR(B.BB_PRESENTATION_FROM,'YYYYMMDD')) INNER JOIN MEDIATE_USER_ATTRIBUTE_INFO MUAI ON A.BB_BRANCH_CODE = RPAD(MUAI.BUTEN_CODE, 4, ' ') AND TO_NUMBER(A.BB_ACCOUNT_NUMBER) = TO_NUMBER(MUAI.ACCOUNT_NUMBER) INNER JOIN CORDYS.T_IPO_PO_ORDER_DETAIL D ON A.BB_PRODUCT_CODE = D.PRODUCT_CODE AND A.BB_PRESENTATION_FROM = D.PRESENTATION_FROM AND A.BB_BRANCH_CODE = RPAD(D.BUTEN_CODE, 4, ' ') AND TO_NUMBER(A.BB_ACCOUNT_NUMBER) = TO_NUMBER(D.ACCOUNT_NUMBER) WHERE 1 = 1
AND D.ORDER_STATUS = #{orderStatus}
AND NVL(D.UPDATE_TIME, D.CREATE_TIME) <= TO_DATE(#{sysDate}, 'yyyyMMddhh24miss')
AND D.BUTEN_CODE || LPAD(D.ACCOUNT_NUMBER, 7, 0) || D.PRODUCT_CODE BETWEEN #{minKey} AND #{maxKey}
